// Build WhatsApp reminder message for each patient
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  let messageText = '';

  if (d.reminder_type === '24h') {
    messageText = `⏰ *Appointment Reminder*\n\nHi ${d.patient_name}! This is a reminder for your appointment tomorrow:\n\n👨‍⚕️ Doctor: ${d.doctor_name}\n📋 ${d.specialization}\n📅 Date: ${d.appointment_date}\n🕐 Time: ${d.display_time}\n🏥 ${d.clinic_name}\n\n📍 Please arrive 10 minutes early.\n\nReply *cancel* to cancel or *reschedule* to change your appointment.`;
  } else if (d.reminder_type === '1h') {
    messageText = `🔔 *Your appointment is in 1 hour!*\n\nHi ${d.patient_name}, just a quick reminder:\n\n👨‍⚕️ ${d.doctor_name} | 🕐 ${d.display_time}\n\nSee you soon! 😊`;
  } else if (d.reminder_type === 'followup') {
    messageText = `👋 *Follow-up Reminder*\n\nHi ${d.patient_name}! Hope you're feeling better after your visit with ${d.doctor_name}.\n\nWould you like to book a follow-up appointment?\n\nReply *book* to schedule.`;
  }

  results.push({
    reminder_id: d.reminder_id,
    patient_phone: d.patient_phone,
    payload: {
      messaging_product: 'whatsapp',
      to: d.patient_phone,
      type: 'text',
      text: { body: messageText }
    }
  });
}

return results;
